/**
 * MedX progress runtime — runs on `npm run start` via medx-runtime-registry.cjs
 * Linear and circular progress for uploads, sync jobs, and order fulfillment stages.
 */
const PROGRESS_VARIANTS = Object.freeze({
  default: { track: "bg-muted", fill: "bg-primary" },
  success: { track: "bg-muted", fill: "bg-emerald-500" },
  warning: { track: "bg-muted", fill: "bg-amber-500" },
  destructive: { track: "bg-muted", fill: "bg-destructive" },
});

const FULFILLMENT_STAGES = Object.freeze([
  { key: "ordered", label: "Order placed", weight: 10 },
  { key: "allocated", label: "Stock allocated", weight: 20 },
  { key: "picked", label: "Picked & packed", weight: 25 },
  { key: "shipped", label: "Shipped", weight: 25 },
  { key: "in-transit", label: "In transit", weight: 10 },
  { key: "delivered", label: "Delivered", weight: 10 },
]);

const progressInstances = new Map();

function clamp(value, min = 0, max = 100) {
  return Math.min(max, Math.max(min, value));
}

function createProgress(config) {
  const id = config.id ?? `medx-progress-${progressInstances.size + 1}`;
  const instance = {
    id,
    value: clamp(config.value ?? 0),
    max: config.max ?? 100,
    variant: config.variant ?? "default",
    styles: PROGRESS_VARIANTS[config.variant ?? "default"],
    label: config.label ?? null,
    showValue: config.showValue ?? true,
    indeterminate: Boolean(config.indeterminate),
    stages: config.stages ?? null,
    currentStage: config.currentStage ?? null,
    startedAt: config.value > 0 ? Date.now() : null,
    completedAt: null,
  };
  progressInstances.set(id, instance);
  return instance;
}

function setProgressValue(id, value) {
  const instance = progressInstances.get(id);
  if (!instance) return null;
  instance.value = clamp(value, 0, instance.max);
  if (instance.value > 0 && !instance.startedAt) instance.startedAt = Date.now();
  if (instance.value >= instance.max) instance.completedAt = Date.now();
  return getProgressPercent(id);
}

function advanceStage(id) {
  const instance = progressInstances.get(id);
  if (!instance || !instance.stages) return null;
  const currentIndex = instance.stages.findIndex((s) => s.key === instance.currentStage);
  const nextIndex = currentIndex + 1;
  if (nextIndex >= instance.stages.length) {
    setProgressValue(id, instance.max);
    return { done: true, stage: instance.stages[instance.stages.length - 1] };
  }
  const next = instance.stages[nextIndex];
  instance.currentStage = next.key;
  const totalWeight = instance.stages.reduce((sum, s) => sum + s.weight, 0);
  const completedWeight = instance.stages
    .slice(0, nextIndex + 1)
    .reduce((sum, s) => sum + s.weight, 0);
  setProgressValue(id, (completedWeight / totalWeight) * instance.max);
  return { done: false, stage: next };
}

function getProgressPercent(id) {
  const instance = progressInstances.get(id);
  if (!instance) return null;
  return {
    id: instance.id,
    percent: instance.max > 0 ? (instance.value / instance.max) * 100 : 0,
    label: instance.label,
    currentStage: instance.currentStage,
    indeterminate: instance.indeterminate,
  };
}

async function runMedxProgress() {
  console.log("[medx:ui:progress] runtime initialized");
  console.log(`[medx:ui:progress] stages=${FULFILLMENT_STAGES.length}`);

  const upload = createProgress({ label: "CSV import", value: 0, variant: "default" });
  for (let v = 0; v <= 100; v += 25) setProgressValue(upload.id, v);

  const fulfillment = createProgress({
    label: "Order #ORD-8842",
    stages: FULFILLMENT_STAGES,
    currentStage: "ordered",
    max: 100,
    variant: "success",
  });
  for (let i = 0; i < 4; i++) advanceStage(fulfillment.id);

  const sync = createProgress({ label: "Blockchain sync", indeterminate: true });

  console.log(`[medx:ui:progress] instances=${progressInstances.size}`);
  console.log("[medx:ui:progress] fulfillment", getProgressPercent(fulfillment.id));
  console.log("[medx:ui:progress] sync indeterminate=", sync.indeterminate);
  console.log("[medx:ui:progress] bootstrap complete");
}

module.exports = runMedxProgress;
